// PlayerStats.cs
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public float MaxHealth = 100f;
    public float CurrentHealth;
    public int Currency;

    void Start()
    {
        CurrentHealth = MaxHealth;
        Debug.Log($"Player initialized with Health: {CurrentHealth}, Currency: {Currency}");
    }

    public void TakeDamage(float amount)
    {
        if (amount < 0) return;

        CurrentHealth -= amount;
        if (CurrentHealth < 0)
        {
            CurrentHealth = 0;
            Debug.Log("Player defeated!");
            // Implement game over logic here
        }
        Debug.Log($"Player took {amount} damage. Current Health: {CurrentHealth}");
    }

    public void Heal(float amount)
    {
        if (amount < 0) return;

        CurrentHealth += amount;
        if (CurrentHealth > MaxHealth)
        {
            CurrentHealth = MaxHealth;
        }
        Debug.Log($"Player healed {amount}. Current Health: {CurrentHealth}");
    }

    public bool TrySpendCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Attempted to spend negative currency.");
            return false;
        }

        if (Currency >= amount)
        {
            Currency -= amount;
            Debug.Log($"Spent {amount} currency. Remaining: {Currency}");
            return true;
        }
        else
        {
            Debug.Log($"Not enough currency to spend {amount}. Current: {Currency}");
            return false;
        }
    }

    public void GainCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Attempted to gain negative currency.");
            return;
        }

        Currency += amount;
        Debug.Log($"Gained {amount} currency. Total: {Currency}");
    }
}

// ShopManager.cs
using UnityEngine;
using System.Collections.Generic;

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public List<ShopItem> availableItems = new List<ShopItem>();

    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
            if (playerStats == null)
            {
                Debug.LogError("PlayerStats not found! Please assign it in the Inspector or ensure a PlayerStats component exists in the scene.");
                enabled = false;
                return;
            }
        }

        if (availableItems.Count == 0)
        {
            availableItems.Add(new ShopItem("Small Health Potion", 50, 25f, 0, "Restores 25 health."));
            availableItems.Add(new ShopItem("Large Health Potion", 150, 75f, 0, "Restores 75 health."));
            availableItems.Add(new ShopItem("Gold Pack (100)", 10, 0, 100, "Adds 100 gold to your wallet."));
            availableItems.Add(new ShopItem("Gold Pack (500)", 40, 0, 500, "Adds 500 gold to your wallet."));
            availableItems.Add(new ShopItem("Mystery Box", 200, 10f, 50, "A box of mystery! Small health and some gold."));
        }

        Debug.Log("Shop Manager initialized.");
    }

    public bool PurchaseItem(ShopItem item)
    {
        if (playerStats == null)
        {
            Debug.LogError("PlayerStats is not assigned to ShopManager!");
            return false;
        }

        if (item == null)
        {
            Debug.LogError("Attempted to purchase a null item.");
            return false;
        }

        Debug.Log($"Attempting to purchase {item.ItemName} for {item.Price} currency.");

        if (playerStats.TrySpendCurrency(item.Price))
        {
            if (item.HealthEffect > 0)
            {
                playerStats.Heal(item.HealthEffect);
            }
            if (item.CurrencyEffect > 0)
            {
                playerStats.GainCurrency(item.CurrencyEffect);
            }

            Debug.Log($"Successfully purchased {item.ItemName}. Player Currency: {playerStats.Currency}, Health: {playerStats.CurrentHealth}");
            return true;
        }
        else
        {
            Debug.Log($"Failed to purchase {item.ItemName}. Not enough currency.");
            return false;
        }
    }

    public void PurchaseItemByName(string itemName)
    {
        ShopItem itemToPurchase = availableItems.Find(item => item.ItemName == itemName);
        if (itemToPurchase != null)
        {
            PurchaseItem(itemToPurchase);
        }
        else
        {
            Debug.LogWarning($"Item '{itemName}' not found in shop.");
        }
    }

    public void SimulateDamage(float amount)
    {
        if (playerStats != null)
        {
            playerStats.TakeDamage(amount);
        }
        else
        {
            Debug.LogError("PlayerStats is not assigned to ShopManager for damage simulation!");
        }
    }
}